```

2. Create a new module and controller for the Stripe webhook using the NestJS CLI:

```sh
nest generate module stripe-webhook
nest generate controller stripe-webhook
```

3. Update your `stripe-webhook.controller.ts` file to handle Stripe webhook events and call your `UserService.createBooking` method to create a booking along with the user when a payment is created using the Checkout page:

```typescript
import { Controller, Post, Req, Res } from '@nestjs/common';
import { Request, Response } from 'express';
import Stripe from 'stripe';
import { UserService } from '../user/user.service';

const stripe = new Stripe('your_stripe_secret_key', { apiVersion: '2020-08-27' });

@Controller('stripe-webhook')
export class StripeWebhookController {
  // Replace 'your_webhook_signing_key' with the signing key from your Stripe Dashboard
  private endpointSecret = 'your_webhook_signing_key';

  constructor(private readonly userService: UserService) {}

  @Post()
  async handleStripeWebhook(@Req() req: Request, @Res() res: Response) {
    const sig = req.headers['stripe-signature'];
    let event;

    try {
      event = stripe.webhooks.constructEvent(req.body, sig, this.endpointSecret);
    } catch (err) {
      res.status(400).send(`Webhook Error: ${err.message}`);
      return;
    }

    if (event.type === 'checkout.session.completed') {
      const session = event.data.object;
      const paymentIntentId = session.payment_intent;

      // Retrieve or create the user with their email
      const userEmail = session.customer_details.email;
      const user = await this.userService.findOrCreateUserByEmail(userEmail);

      // Create a booking associated with the user and store the PaymentIntent ID
      await this.userService.createBooking(user.id, paymentIntentId);
    }

    return res.json({ received: true });
  }
}
```

